import React, { useEffect, useState } from "react";
import {
  Modal,
  View,
  Text,
  StyleSheet,
  Pressable,
  TextInput,
  TouchableOpacity,
  Platform,
} from "react-native";
import { useTranslation } from "../i18n";

export default function SecretCodeModal({ visible, onClose, onConfirm }) {
  const { t } = useTranslation();
  const [code, setCode] = useState("");

  useEffect(() => {
    if (!visible) setCode("");
  }, [visible]);

  return (
    <Modal visible={visible} transparent animationType="fade" onRequestClose={onClose}>
      <Pressable style={S.backdrop} onPress={onClose}>
        <Pressable style={S.sheet} onPress={() => {}}>
          <Text style={S.title}>{t("modal.enterSecretCode")}</Text>

          <TextInput
            value={code}
            onChangeText={setCode}
            placeholder={t("modal.placeholder")}
            placeholderTextColor="rgba(17,24,39,0.35)"
            style={S.input}
            autoFocus
            keyboardType={Platform.OS === "ios" ? "number-pad" : "numeric"}
            returnKeyType="done"
            secureTextEntry
            maxLength={12}
          />

          <View style={S.actions}>
            <TouchableOpacity style={[S.btn, S.btnGhost]} onPress={onClose} activeOpacity={0.9}>
              <Text style={[S.btnText, S.btnTextGhost]}>{t("common.cancel")}</Text>
            </TouchableOpacity>

            <TouchableOpacity
              style={[S.btn, S.btnPrimary, !code.trim() && { opacity: 0.5 }]}
              onPress={() => onConfirm(code.trim())}
              activeOpacity={0.9}
              disabled={!code.trim()}
            >
              <Text style={[S.btnText, S.btnTextPrimary]}>{t("common.confirm")}</Text>
            </TouchableOpacity>
          </View>
        </Pressable>
      </Pressable>
    </Modal>
  );
}

const DARK_GREEN = "#0F3C2F";

const S = StyleSheet.create({
  backdrop: {
    flex: 1,
    backgroundColor: "rgba(0,0,0,0.45)",
    justifyContent: "center",
    alignItems: "center",
    padding: 18,
  },
  sheet: {
    width: "100%",
    maxWidth: 420,
    backgroundColor: "#FFFFFF",
    borderRadius: 18,
    padding: 18,
    shadowColor: "#000",
    shadowOpacity: 0.18,
    shadowRadius: 18,
    shadowOffset: { width: 0, height: 14 },
    elevation: 10,
  },
  title: {
    fontSize: 18,
    fontWeight: "800",
    color: "#111827",
    marginBottom: 12,
    textAlign: "center",
  },
  input: {
    height: 46,
    borderRadius: 14,
    borderWidth: 1,
    borderColor: "rgba(0,0,0,0.10)",
    backgroundColor: "rgba(0,0,0,0.04)",
    paddingHorizontal: 14,
    fontSize: 16,
    fontWeight: "700",
    color: "#111827",
    textAlign: "center",
    letterSpacing: 2,
    marginBottom: 14,
  },
  actions: {
    flexDirection: "row",
    gap: 10,
  },
  btn: {
    flex: 1,
    height: 42,
    borderRadius: 14,
    alignItems: "center",
    justifyContent: "center",
  },
  btnGhost: {
    backgroundColor: "rgba(0,0,0,0.06)",
  },
  btnPrimary: {
    backgroundColor: DARK_GREEN,
  },
  btnText: {
    fontSize: 14,
    fontWeight: "800",
    letterSpacing: 0.2,
  },
  btnTextGhost: {
    color: "#111827",
  },
  btnTextPrimary: {
    color: "#FFFFFF",
  },
});
